import{_ as e,o as n,c as t,a2 as i}from"./chunks/framework.CHeM0PsO.js";const k=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"arsitektur/sistem-keamanan.md","filePath":"arsitektur/sistem-keamanan.md","lastUpdated":1784467494000}'),r={name:"arsitektur/sistem-keamanan.md"};function o(s,a,l,m,d,u){return n(),t("div",null,[...a[0]||(a[0]=[i('<h2 id="bab-13-sistem-keamanan-perlindungan-data" tabindex="-1">BAB 13: SISTEM KEAMANAN &amp; PERLINDUNGAN DATA <a class="header-anchor" href="#bab-13-sistem-keamanan-perlindungan-data" aria-label="Permalink to &quot;BAB 13: SISTEM KEAMANAN &amp; PERLINDUNGAN DATA&quot;">​</a></h2><h3 id="_13-1-anti-double-submit-race-condition-lock" tabindex="-1">13.1 Anti Double-Submit (Race-Condition Lock) <a class="header-anchor" href="#_13-1-anti-double-submit-race-condition-lock" aria-label="Permalink to &quot;13.1 Anti Double-Submit (Race-Condition Lock)&quot;">​</a></h3><p>Setelah SPV menekan tombol &quot;Kirim&quot;, sistem mengunci pengiriman selama <strong>10 detik</strong>. Jika SPV menekan lagi dalam 10 detik, muncul pesan: &quot;Pengiriman terlalu cepat (Spam klik). Laporan sedang diproses.&quot;</p><h3 id="_13-2-anti-duplikasi-laporan" tabindex="-1">13.2 Anti Duplikasi Laporan <a class="header-anchor" href="#_13-2-anti-duplikasi-laporan" aria-label="Permalink to &quot;13.2 Anti Duplikasi Laporan&quot;">​</a></h3><p>Sebelum menyimpan laporan baru, sistem memeriksa apakah sudah ada laporan dengan ID yang sama di database. Jika ada, laporan ditolak: &quot;Laporan untuk periode ini sudah ada. Pengiriman ganda digagalkan!&quot;</p><h3 id="_13-3-anti-kontaminasi-silang-draft" tabindex="-1">13.3 Anti Kontaminasi Silang Draft <a class="header-anchor" href="#_13-3-anti-kontaminasi-silang-draft" aria-label="Permalink to &quot;13.3 Anti Kontaminasi Silang Draft&quot;">​</a></h3><p>Jika SPV login di outlet A, namun browser masih menyimpan draft dari outlet B (misalnya karena kemarin pinjam HP), sistem otomatis membuang draft yang tidak cocok. Data outlet lain tidak akan pernah tercampur.</p><h3 id="_13-4-self-healing-penanganan-data-hilang" tabindex="-1">13.4 Self-Healing: Penanganan Data Hilang <a class="header-anchor" href="#_13-4-self-healing-penanganan-data-hilang" aria-label="Permalink to &quot;13.4 Self-Healing: Penanganan Data Hilang&quot;">​</a></h3><p>Jika file Draft JSON (Fase 1) hilang dari Google Drive (misalnya karena terhapus manual), sistem akan:</p><ol><li>Mendeteksi bahwa draft tidak ditemukan</li><li>Otomatis menghapus baris &quot;menggantung&quot; di Spreadsheet</li><li>Memberitahu SPV: &quot;Data Fase 1 tidak ditemukan. Sistem telah menghapus status gantung Anda. Silakan buat ulang laporan.&quot;</li></ol><h3 id="_13-5-perlindungan-form-tidak-ada-reset-prematur" tabindex="-1">13.5 Perlindungan Form: Tidak Ada Reset Prematur <a class="header-anchor" href="#_13-5-perlindungan-form-tidak-ada-reset-prematur" aria-label="Permalink to &quot;13.5 Perlindungan Form: Tidak Ada Reset Prematur&quot;">​</a></h3><p>Sistem <strong>TIDAK</strong> akan menghapus data yang sudah diketik SPV sebelum server memastikan laporan berhasil tersimpan. Jika koneksi terputus, semua data tetap aman di layar — SPV tinggal tekan &quot;Kirim&quot; lagi.</p><h3 id="_13-6-timezone-safe-date-parsing" tabindex="-1">13.6 Timezone-Safe Date Parsing <a class="header-anchor" href="#_13-6-timezone-safe-date-parsing" aria-label="Permalink to &quot;13.6 Timezone-Safe Date Parsing&quot;">​</a></h3><p>Semua pemrosesan tanggal di server menggunakan metode pemotongan teks (string split), <strong>bukan</strong> konversi objek tanggal (Date object). Ini mencegah bug di mana server Google (yang beroperasi di zona waktu UTC) menggeser tanggal mundur 1 hari.</p><p>Contoh: Tanggal &quot;1 Desember 2026&quot; yang dikirim dari HP di Makassar (WITA, UTC+8) bisa berubah menjadi &quot;30 November 2026&quot; jika diproses sebagai objek Date di server UTC. Dengan metode pemotongan teks, hal ini <strong>tidak akan pernah terjadi</strong>.</p><hr>',16)])])}const p=e(r,[["render",o]]);export{k as __pageData,p as default};
